import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Constructing safe HTML content
        String outputHtml = "<html><body>" + sanitizedInput + "</body></html>";

        try {
            // Writing the safe HTML content to a file
            FileWriter fileWriter = new FileWriter("output.html");
            fileWriter.write(outputHtml);
            fileWriter.close();

            System.out.println("Safe HTML file generated successfully.");
        } catch (IOException e) {
            System.out.println("Error writing output HTML file: " + e.getMessage());
        }
    }
}

